export function generateGameToken(config) {
  const contractName = config.contractName || 'MonadGame';
  const currencyName = config.currencyName || 'Game Gold';
  const currencySymbol = config.currencySymbol || 'GOLD';
  const itemName = config.itemName || 'Game Items';

  return `// SPDX-License-Identifier: MIT
// Generated by MONAD_BUILD.exe — NX Terminal
// Target: Monad (Chain ID 143)
// Compiler: solc ^0.8.28, evmVersion: "prague"
//
// MONAD OPTIMIZATION NOTES:
// - Monad charges gas based on gas LIMIT, not gas used. Set tight limits.
// - Cold SLOAD costs 8,100 gas (vs 2,100 on Ethereum). Cache storage reads.
// - Monad's 400ms block time enables real-time game interactions.

pragma solidity ^0.8.28;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC1155/ERC1155.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/// @title ${currencyName} — In-game currency
contract ${contractName}Currency is ERC20, Ownable {
    constructor(address initialOwner)
        ERC20("${currencyName}", "${currencySymbol}")
        Ownable(initialOwner)
    {}

    function mint(address to, uint256 amount) public onlyOwner {
        _mint(to, amount);
    }

    function burn(uint256 amount) public {
        _burn(msg.sender, amount);
    }
}

/// @title ${itemName} — Game item NFTs (ERC-1155)
contract ${contractName}Items is ERC1155, Ownable, ReentrancyGuard {
    // Item type constants
    uint256 public constant SWORD = 0;
    uint256 public constant SHIELD = 1;
    uint256 public constant POTION = 2;
    uint256 public constant ARMOR = 3;

    // Item prices in game currency
    mapping(uint256 => uint256) public itemPrices;

    // Game currency token
    ${contractName}Currency public immutable currency;

    event ItemPurchased(address indexed player, uint256 itemId, uint256 amount);
    event ItemCrafted(address indexed player, uint256 itemId);

    constructor(
        address initialOwner,
        address currencyAddress
    )
        ERC1155("https://game.example.com/api/item/{id}.json")
        Ownable(initialOwner)
    {
        currency = ${contractName}Currency(currencyAddress);

        // Set default prices
        itemPrices[SWORD] = 100 * 1e18;
        itemPrices[SHIELD] = 80 * 1e18;
        itemPrices[POTION] = 10 * 1e18;
        itemPrices[ARMOR] = 150 * 1e18;
    }

    function buyItem(uint256 itemId, uint256 amount) external nonReentrant {
        uint256 price = itemPrices[itemId]; // Cache cold SLOAD
        require(price > 0, "Item not for sale");

        uint256 totalCost = price * amount;
        currency.transferFrom(msg.sender, address(this), totalCost);
        _mint(msg.sender, itemId, amount, "");

        emit ItemPurchased(msg.sender, itemId, amount);
    }

    function setItemPrice(uint256 itemId, uint256 price) external onlyOwner {
        itemPrices[itemId] = price;
    }

    function mintItem(address to, uint256 itemId, uint256 amount) external onlyOwner {
        _mint(to, itemId, amount, "");
    }

    function setURI(string memory newuri) external onlyOwner {
        _setURI(newuri);
    }
}
`;
}
